import{_ as t,o as e,c as a,a2 as o}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Notifications","description":"","frontmatter":{},"headers":[],"relativePath":"projects/arti/contracts/notifications.md","filePath":"projects/arti/contracts/notifications.md"}'),l={name:"projects/arti/contracts/notifications.md"};function r(n,i,s,c,d,p){return e(),a("div",null,[...i[0]||(i[0]=[o('<h1 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h1><p><strong>状态：Current</strong></p><p><strong>核对日期：2026-06-15</strong></p><p><strong>Owner：<code>arti</code></strong></p><h2 id="核心不变量" tabindex="-1">核心不变量 <a class="header-anchor" href="#核心不变量" aria-label="Permalink to &quot;核心不变量&quot;">​</a></h2><ul><li>所有服务端写入统一调用 <code>notify_user()</code>。</li><li>不允许业务代码裸 <code>INSERT INTO notifications</code>。</li><li>每个可重试事件必须提供稳定 <code>dedupe_key</code>。</li><li>通知类型字符串以主站注册表为准。</li><li>DB 不用硬编码的 Type CHECK 代替应用注册表。</li><li>表 schema 只由 Owner 仓库 migration 修改。</li></ul><h2 id="写入者" tabindex="-1">写入者 <a class="header-anchor" href="#写入者" aria-label="Permalink to &quot;写入者&quot;">​</a></h2><ul><li><code>report_tasks</code> 终态通过 DB trigger 产生报告通知。</li><li>预测结算任务按用户聚合通知。</li><li>Credits 和市场结算 RPC 产生对应通知。</li><li><code>ARTi-poly</code> 可以调用公共 helper，但不拥有共享表 DDL。</li></ul><h2 id="读取者" tabindex="-1">读取者 <a class="header-anchor" href="#读取者" aria-label="Permalink to &quot;读取者&quot;">​</a></h2><p>主站负责：</p><ul><li>未读数量和 Realtime 订阅</li><li>类型到图标、文案和站内路由的映射</li><li>未知类型的安全 fallback</li><li>标记单条或全部已读</li></ul><p>通知到达和页面内结果展示可以并存，但必须避免重复副作用。</p><h2 id="dedupe-key" tabindex="-1">Dedupe Key <a class="header-anchor" href="#dedupe-key" aria-label="Permalink to &quot;Dedupe Key&quot;">​</a></h2><p>推荐格式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;type&gt;:&lt;business-id&gt;[:&lt;scope&gt;]</span></span></code></pre></div><p>示例：</p><ul><li><code>report_done:&lt;task-id&gt;</code></li><li><code>prediction_settled:&lt;user-id&gt;:&lt;date&gt;</code></li><li><code>credits_result:&lt;market-id&gt;:&lt;user-id&gt;</code></li></ul><h2 id="修改检查" tabindex="-1">修改检查 <a class="header-anchor" href="#修改检查" aria-label="Permalink to &quot;修改检查&quot;">​</a></h2><ul><li>新类型是否加入注册表和测试</li><li>写入是否走 <code>notify_user</code></li><li>是否需要 Toast</li><li>跳转目标是否为站内 canonical route</li><li>重试是否产生重复通知</li><li>Poly 和主站是否都能读取</li></ul><h2 id="实现真源" tabindex="-1">实现真源 <a class="header-anchor" href="#实现真源" aria-label="Permalink to &quot;实现真源&quot;">​</a></h2><ul><li><a href="https://github.com/iloveopt/arti/blob/main/docs/rfcs/0013-notification-system.md" target="_blank" rel="noreferrer">Global notification RFC</a></li><li><a href="https://github.com/iloveopt/arti/blob/main/src/lib/notification-kind.ts" target="_blank" rel="noreferrer">Notification registry</a></li><li><a href="https://github.com/iloveopt/arti/blob/main/supabase/migrations/20260611150000_notification_system.sql" target="_blank" rel="noreferrer"><code>notify_user</code> migration</a></li></ul>',21)])])}const f=t(l,[["render",r]]);export{u as __pageData,f as default};
